<template>
<div class="head-portrait">
  <div class="box" @mouseenter="enter()" @mouseleave="leave()">
    <!-- 占位白色图片 -->
    <img class="picture_bottom" :src="ready.head_ready" />
    
    <transition name="main">
      <div class="main" v-if="mainIsShow">
        <transition :name="around ? 'next_into' : 'back_into'">
          <img 
            class="picture"
            :src="src[i1]"
            v-show="isShow"
          >
        </transition>
        <transition :name="around ? 'next_into' : 'back_into'">
          <img 
            class="picture"
            :src="src[i2]"
            v-show="!isShow"
          >
        </transition>
      </div>
    </transition>
  </div>

  <!-- 箭头 -->
  <span class="left" v-text="'<'" @click="back()" @mouseenter="enter()" @mouseleave="leave()" />
  <span class="right" v-text="'>'" @click="next()" @mouseenter="enter()" @mouseleave="leave()" />

  <p class="describe">个人照片</p>
</div>
</template>

<script>
import imgReady from 'ts/shopping/imgReady'

export default {
  name: 'head-portrait',
  props: {
    ready: Object
  },
  data() {
    return {
      mainIsShow: false, // 主要内容是否显示
      around: true, // 前后动画顺序
      once: 7000, // 执行一次动画间隔
      next_time: 1200, // 动画时间，取最大值，配合css进行修改 
      back_time: 400, // 动画时间，取最大值，配合css进行修改 
      loop: '', // 循环
      i1: 0, // 第一张图片的下标
      i2: 1, // 第二张图片的下标
      max: 2, // 最大图片下标数，第一张图从零开始数
      isButton: true, // 按钮是否可以点击
      isShow: true, // 控制图片显示
      src: [
        "https://z3.ax1x.com/2021/08/16/fWBqAI.jpg",
        "https://z3.ax1x.com/2021/08/16/fWBLNt.jpg",
        "https://z3.ax1x.com/2021/08/16/fWBj9f.jpg",
      ]
    }
  },
  mounted() {
    new imgReady([this.src[0], this.src[1]])
    .load().then((src) => {
      this.mainIsShow = true;
      // 开始动画
      this.leave()

      // 加载剩余的图片
      let surplus = []
      for (let index = 2; index < this.src.length; index++) {
        surplus.push(this.src[index])
      }
      new imgReady(surplus).load()
    })

    // 页面获得焦点时，继续轮播图
    window.onfocus = () => {
      this.$store.commit('on_off_change', true)
    }

    // 页面失去焦点时，停止轮播图
    window.onblur = () => {
      this.$store.commit('on_off_change', false)
    }
  },
  methods: {
    // 鼠标进入停止循环
    enter() {
      clearTimeout(this.loop)
    },
    // 鼠标离开继续循环
    leave() {
      this.loop = setInterval(() => {
        this.next()
      }, this.once)
    },
    // 淡入淡出切换
    into() {
      this.isShow = !this.isShow
    },
    // 下一张图片
    next() {
      // 如果当前按钮不可点击，退出方法
      if(this.isButton == false) {
        return
      }

      // 如果不允许轮播图执行，退出方法
      if(this.$store.state.banner.on_off == false) {
        return
      }
      
      // 执行下一个动画
      this.around = true

      new Promise(resolve => {
        // 执行动作，按钮不可点击
        this.isButton = false
        // 淡入淡出
        this.into()
        // 淡入淡出后，等待动画完成
        setTimeout(() => {
          // 下一步
          resolve()
        }, this.next_time)
      }).then(() => { 
        // 第一张图隐藏时执行src切换
        if(this.isShow == false) {
          // 另一个下标不超过图片最大值，本下标为另一个加一
          if(this.i2 < this.max) {
            this.i1 = this.i2 + 1
          } else { // 如果达到最大值，下标归零
            this.i1 = 0
          }
        } else { // 如果第一张图片正在显示，第二张图片开始切换
          if(this.i1 < this.max) {
            this.i2 = this.i1 + 1
          } else {
            this.i2 = 0
          }
        }

        // 执行动作完毕，按钮可点击
        this.isButton = true
      })

    },
    // 上一张图片
    back() {
      // 如果当前按钮不可点击，退出方法
      if(this.isButton == false) {
        return
      }
      
      // 执行上一个动画
      this.around = false

      // 部分相反逻辑
      // 执行动作，按钮不可点击
      this.isButton = false

      // 先进行 src 切换 
      // 第一张图片
      if(this.isShow == false) {
        // 另一个下标大于 0，本下标为另一个减一
        if(this.i2 > 0) {
          this.i1 = this.i2 - 1
        } else { // 如果小于等于 0，下标变为最大值
          this.i1 = this.max
        }
      } else { // 第二张图片
        if(this.i1 > 0) {
          this.i2 = this.i1 - 1
        } else { // 如果小于等于 0，下标变为最大值
          this.i2 = this.max
        }
      }

      new Promise(resolve => {
        // 淡入淡出
        this.into()
        // 淡入淡出后，等待动画完成
        setTimeout(() => {
          // 下一步
          resolve()
        }, this.back_time)
      }).then(() => { 
        // 执行动作完毕，按钮可点击
        this.isButton = true
      })
    }
  }
}
</script>

