          v-show="show"
          title="微信二维码"
        />
      </transition>
      <transition name="picture2">
        <img
          class="img2"
          :src="src[1]" 
          v-show="!show"
          title="QQ二维码"
        />
      </transition>
    </div>
  </transition>

  <!-- 二维码文字提示 -->
  <transition class="t1" name="tips1">
    <p v-if="!show">QQ</p>
  </transition>
  <transition class="t2" name="tips2">
    <p v-if="show">微信</p>
  </transition>

  <!-- 占位图，全透明 -->
  <img
    class="img0" 
    :src="ready.qr_code_ready"
  />

  <!-- 触发事件的按钮 -->
  <rotate class="rotate" @click="replace()" />
</div>

  <p class="def">
    <span>{{ show ? "微信" : "QQ" }}</span>二维码
