<script>
import rotate from './rotate.vue'
import imgReady from 'ts/shopping/imgReady'

export default {
  name: 'QR-code',
  props: {
    ready: Object
  },
  data() {
    return {
      r: true,
      show: true,
      isShow: false,
      mainShow: false,
      showOne: true,
      src: [
        "https://z3.ax1x.com/2021/08/16/fWBxgS.png", // 微信
        "https://z3.ax1x.com/2021/08/16/fWBv38.png" // QQ
      ]
    }
  },
  mounted() {
    new imgReady(this.src)
    .load().then((src) => {
      this.isShow = true;
    })
  },
  methods: {
    // 切换事件
    replace() {
      // 限制点击速度
      if(this.r) {
        this.r = false

        this.show = !this.show;
        // 动画执行完成以后允许再次点击
        setTimeout(() => {
          this.r = true
        }, 500)
      }
    }
  },
  components: {
    rotate
  }
}
</script>

