// 简略介绍，首页，结构未抽离
<template>
<transition name="open-box">
  <!-- 盒子大小由占位撑开 -->
  <div class="open-box m-container" v-if="isShow">
    <!-- 五颜六色背景 -->
    <background-paper />
    <!-- 占位 -->
    <div class="brief seize-a-seat flex-cont-md flex-cont-sm">
      <resume-left class="resume-left flex-md-3 flex-sm-1" :ready="ready" />
      <resume-right class="resume-right flex-md-8 flex-sm-1" />
    </div>
    <!-- 首页显示内容 -->
    <transition :name="intro">
      <div class="brief intro m-cont flex-cont-md flex-cont-sm" v-if="$store.state.Intro.working.i == 0" >
        <resume-left class="resume-left flex-md-3 flex-sm-1" :ready="ready" />
        <resume-right class="resume-right flex-md-8 flex-sm-1" />
      </div>
    </transition>
    <!-- 维护页 -->
    <transition :name="intro">
      <maintain class="intro m-cont" v-if="$store.state.Intro.working.i == 1" />
    </transition>
  </div>
</transition>

<next ref="next" @click="next()" />
<back ref="back" @click="back()" />

</template>

<script>
import backgroundPaper from '../background-paper.vue'
import resumeLeft from './left/left.vue'
import resumeRight from './right/right.vue'
import imgReady from 'ts/shopping/imgReady'
import next from '../next.vue'
import back from '../back.vue'

import maintain from '../maintain.vue'

export default {
  name: "brief",
  components: {
    backgroundPaper,
    resumeLeft,
    resumeRight,
    next,
    back,
    maintain
  },
  data() {
    return {
      isShow: false,
      intro: "next",
      imgs: [
        "https://z3.ax1x.com/2021/08/12/fdcZHe.jpg", // head_ready 头像预留图
        "https://z3.ax1x.com/2021/08/12/fdcEnO.jpg", // qr_code_ready 二维码预留图
      ],
      ready: {
        head_ready: String,
        qr_code_ready: String
      }
    }
  },
  mounted() {
    new imgReady(this.imgs)
    .load().then((src) => {
      this.ready.head_ready = src[0]
      this.ready.qr_code_ready = src[1]

      this.isShow = true;

      this.$refs.next.show()
      this.$refs.back.show()
    })
  },
  methods: {
    next() {
      this.intro = "next"
      this.$store.commit('next')
    },
    back() {
      this.intro = "back"
      this.$store.commit('back')
    }
  }
}
</script>

<style lang="less" scoped>
.brief {
  display: flex;
}
.intro {
  position: absolute;
  top: 0;
  left: 0;
  transform: translateZ(0);
  z-index: 1;
  box-shadow: @body-shadow;
}
.seize-a-seat {
  opacity: 0;
  position: relative;
  top: 0;
  left: 0;
  z-index: -1000000;
}

.resume-left {
  z-index: 1;
  background-color: @lan;
}
.resume-right {
  z-index: 0;
  background-color: @bai;
}

.open-box-enter-active {
  animation: open-box-in .33s;
}
@keyframes open-box-in {
  0% {
    opacity: 0;
    margin-top: 50px;
  }
  100% {
    opacity: 1;
    margin-top: 0;
  }
}

// next()
.next-leave-active {
  animation: next-to .77s;
}
@keyframes next-to {
  0% {
    z-index: 10;
  }
  50% {
    opacity: 1;
  }
  100% {
    transform: rotate(-2deg);
    top: -50px;
    left: -100px;
    opacity: 0;
  }
}
// back()
// 进入
.back-enter-active {
  animation: next-to 1s reverse;
}
// 离开
.back-leave-active {
  animation: back-to 1s;
}
@keyframes back-to {
  99% {
    opacity: 1;
  }
  100% {
    opacity: 0;
  }
}

// 宽度小于768px
@media screen and (max-width: 768px) {
  .brief {
    flex-flow: column;
  }
  .background-paper {
    display: none;
  }
}

// 宽度大于1200px 
@media screen and (min-width: 1200px) {
  .open-box, .intro {
    max-height: 1696.8px;
  }
}
</style>