// 字体默认白色
<template>
<div class="project-title">
  <h3>
    <span class="ico" :class="[ico, icoStyle]" />
    <span class="caption" :class="shadowStyle">{{ theme }}</span>
  </h3>
</div>
</template>

<script>
export default {
  name: 'project-title',
  // 传入： ico图标对应的类名， 图标后面显示的文字
  props: {
    ico: String,
    theme: String,
    pattern: {
      type: String,
      default: "0"
    }
  },
  computed: {
    icoStyle() {
      return "ico-" + this.pattern
    },
    shadowStyle() {
      return "shadow-" + this.pattern
    }
  },
}
</script>

